// src/App.js - Update import for AppProviders
import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
// Import existing components
import Navbar from './components/layout/Navbar';
import Footer from './components/layout/Footer';
import Home from './pages/Home';
import Dashboard from './pages/Dashboard';
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';
import Profile from './pages/account/ProfilePage';
import NotFound from './pages/NotFound';
// Import subscription-related components
import PaymentSuccessPage from './pages/subscription/PaymentSuccessPage';
import PaymentCancelPage from './pages/subscription/PaymentCancelPage';
import BasicSuccessPage from './pages/subscription/BasicSuccessPage';
import SubscriptionUpgradePage from './pages/subscription/SubscriptionUpgradePage';
import PricingPlans from './components/subscription/PricingPlans';
import SubscriptionManagement from './components/subscription/SubscriptionManagement';
// Import tier-specific content pages
import BasicContent from './pages/subscription/BasicContent';
import PremiumContent from './pages/subscription/PremiumContent';
import EliteContent from './pages/subscription/EliteContent';
// Import protected route
import ProtectedRoute from './components/auth/ProtectedRoute';

// Import AppProviders as named import
import { AppProviders } from './providers/AppProviders';

function App() {
  return (
    <AppProviders>
      <Router>
        <div className="App">
          <Navbar />
          <main className="main-content">
            <Switch>
              {/* Public routes */}
              <Route exact path="/" component={Home} />
              <Route path="/login" component={Login} />
              <Route path="/register" component={Register} />
              
              {/* Subscription routes */}
              <Route path="/subscription/plans" component={PricingPlans} />
              <Route path="/subscription/success" component={PaymentSuccessPage} />
              <Route path="/subscription/cancel" component={PaymentCancelPage} />
              <Route path="/subscription/basic-success" component={BasicSuccessPage} />
              
              {/* Protected subscription routes */}
              <ProtectedRoute path="/subscription/manage" component={SubscriptionManagement} />
              <ProtectedRoute path="/subscription/upgrade" component={SubscriptionUpgradePage} />
              
              {/* Other protected routes */}
              <ProtectedRoute path="/dashboard" component={Dashboard} />
              <ProtectedRoute path="/profile" component={Profile} />
              
              {/* Tier-specific content */}
              <ProtectedRoute path="/content/basic" component={BasicContent} />
              <ProtectedRoute path="/content/premium" component={PremiumContent} />
              <ProtectedRoute path="/content/elite" component={EliteContent} />
              
              {/* Catch-all for 404 */}
              <Route component={NotFound} />
            </Switch>
          </main>
          <Footer />
        </div>
      </Router>
    </AppProviders>
  );
}

export default App;
